from dataclasses import dataclass
from typing import Optional


@dataclass
class ASTNode:
    type: str
    value: Optional[float] = None
    op: Optional[str] = None
    left: Optional["ASTNode"] = None
    right: Optional["ASTNode"] = None
    operand: Optional["ASTNode"] = None


def parse(expression: str) -> ASTNode:
    tokens = tokenize(expression)
    ast, remaining = parse_expression(tokens)
    if remaining:
        raise ValueError("Invalid expression")
    return ast


def evaluate(node: ASTNode) -> float:
    if node.type == "number":
        assert node.value is not None
        return node.value
    elif node.type == "unary":
        assert node.operand is not None
        operand_value = evaluate(node.operand)
        if node.op == "-":
            return -operand_value
        else:
            raise ValueError(f"Unsupported unary operator: {node.op}")
    elif node.type == "binop":
        assert node.left is not None and node.right is not None
        left_value = evaluate(node.left)
        right_value = evaluate(node.right)
        if node.op == "+":
            return left_value + right_value
        elif node.op == "-":
            return left_value - right_value
        elif node.op == "*":
            return left_value * right_value
        elif node.op == "/":
            if right_value == 0:
                raise ZeroDivisionError("Division by zero")
            return left_value / right_value
        else:
            raise ValueError(f"Unsupported binary operator: {node.op}")
    else:
        raise ValueError(f"Unknown node type: {node.type}")


def tokenize(expression: str) -> list:
    tokens = []
    i = 0
    n = len(expression)

    while i < n:
        c = expression[i]
        if c == " ":
            i += 1
            continue
        elif c in "()+-*/":
            tokens.append(c)
            i += 1
        elif c.isdigit() or c == ".":
            j = i
            while j < n and (expression[j].isdigit() or expression[j] == "."):
                j += 1
            num_str = expression[i:j]
            if "." in num_str and not num_str.replace(".", "").isdigit():
                raise ValueError(f"Invalid number: {num_str}")
            tokens.append(num_str)
            i = j
        else:
            raise ValueError(f"Invalid character: {c}")

    return tokens


def parse_expression(tokens: list) -> tuple[ASTNode, list]:
    node, tokens = parse_add_sub(tokens)
    return node, tokens


def parse_add_sub(tokens: list) -> tuple[ASTNode, list]:
    node, tokens = parse_mul_div(tokens)

    while tokens and tokens[0] in ("+", "-"):
        op = tokens.pop(0)
        right, tokens = parse_mul_div(tokens)
        node = ASTNode(type="binop", op=op, left=node, right=right)

    return node, tokens


def parse_mul_div(tokens: list) -> tuple[ASTNode, list]:
    node, tokens = parse_unary(tokens)

    while tokens and tokens[0] in ("*", "/"):
        op = tokens.pop(0)
        right, tokens = parse_unary(tokens)
        node = ASTNode(type="binop", op=op, left=node, right=right)

    return node, tokens


def parse_unary(tokens: list) -> tuple[ASTNode, list]:
    if tokens and tokens[0] == "-":
        op = tokens.pop(0)
        operand, tokens = parse_unary(tokens)
        return ASTNode(type="unary", op=op, operand=operand), tokens
    elif tokens and tokens[0] == "(":
        tokens.pop(0)
        node, tokens = parse_expression(tokens)
        if not tokens or tokens[0] != ")":
            raise ValueError("Unmatched parentheses")
        tokens.pop(0)
        return node, tokens
    else:
        return parse_number(tokens)


def parse_number(tokens: list) -> tuple[ASTNode, list]:
    if not tokens:
        raise ValueError("Empty input")

    token = tokens.pop(0)
    try:
        value = float(token)
    except ValueError:
        raise ValueError(f"Invalid token: {token}")

    return ASTNode(type="number", value=value), tokens
